        "import matplotlib.pyplot as plt\n",
        "import pandas as pd\n",
        "import numpy as np\n",
        "\n",
        "# 1. Prepare data for the multi-format comparison\n",
        "# audit_data is retrieved from your previous quantum simulation\n",
        "df_audit = pd.DataFrame(audit_data)\n",
        "\n",
        "fig, axes = plt.subplots(1, 3, figsize=(22, 6))\n",
        "\n",
        "# --- Format A: The Line Chart (Gap Analysis) ---\n",
        "axes[0].plot(df_audit['layer'], df_audit['purity'], marker='o', label='Total Purity', color='#0984e3', linewidth=2)\n",
        "axes[0].plot(df_audit['layer'], df_audit['entropy'], marker='x', label='Entropy (Leak)', color='#d63031', linewidth=2)\n",
        "axes[0].fill_between(df_audit['layer'], df_audit['purity'], df_audit['entropy'], color='#00b894', alpha=0.1, label='Stability Zone')\n",
        "axes[0].set_title('A: Line Chart (The Gap Audit)')\n",
        "axes[0].set_ylim(-0.05, 1.1)\n",
        "axes[0].legend()\n",
        "axes[0].grid(True, alpha=0.2)\n",
        "\n",
        "# --- Format B: Standard Bar (Structural Balance) ---\n",
        "axes[1].bar(df_audit['layer'], df_audit['purity'], color='#dfe6e9', label='Purity Capacity')\n",
        "axes[1].bar(df_audit['layer'], df_audit['stability'], color='#00b894', label='Net Stability')\n",
        "axes[1].set_title('B: Standard Bar (Layer Strength)')\n",
        "axes[1].legend()\n",
        "\n",
        "# --- Format C: Stacked Bar (The Zero-Sum Audit) ---\n",
        "# This visualizes Purity = Stability + Entropy directly\n",
        "axes[2].bar(df_audit['layer'], df_audit['stability'], label='Stability (Coherence)', color='#00b894')\n",
        "axes[2].bar(df_audit['layer'], df_audit['entropy'], bottom=df_audit['stability'], label='Entropy (Loss)', color='#d63031')\n",
        "axes[2].set_title('C: Stacked Bar (The Zero-Sum Audit)')\n",
        "axes[2].set_ylabel('Total Purity (1.0)')\n",
        "axes[2].set_ylim(0, 1.1)\n",
        "axes[2].legend()\n",
        "\n",
        "plt.tight_layout()\n",
        "plt.show()\n",
        "\n",
        "print(\"Audit Question: In Chart C, if 'Entropy' increases in a layer, what happens to the 'Stability' portion of that same bar?\")"
