        "# Calculate how much your hardware run deviates from your 'Nucleus' baseline\n",
        "def check_coherence_drop(current_purity, baseline_purity=1.0):\n",
        "    drop = baseline_purity - current_purity\n",
        "    if drop > 0.05:\n",
        "        print(f\"Warning: Significant decoherence detected! Drop: {drop:.3f}\")\n",
        "    return drop\n"
