        "import matplotlib.pyplot as plt\n",
        "import pandas as pd\n",
        "import numpy as np\n",
        "\n",
        "# 1. Prepare data from your latest quantum simulation\n",
        "# Using 'audit_data' which contains layer-wise Purity, Entropy, and Stability\n",
        "df_audit = pd.DataFrame(audit_data)\n",
