        "axes[0].legend()\n",
        "axes[0].grid(True, alpha=0.2)\n",
        "\n",
        "# --- Option 2: Standard Bar (Structural Balance) ---\n",
        "# Best for: Comparing absolute 'strength' or capacity vs actual stability\n",
        "axes[1].bar(df_audit['layer'], df_audit['purity'], color='#dfe6e9', label='Purity Capacity')\n",
