        "        const yArr = [...new Set(grid.map(d => d.strong))].sort((a,b)=>a-b);\n",
        "        const zMat = yArr.map(y => xArr.map(x => {\n",
        "            const match = grid.find(d => d.em === x && d.strong === y);\n",
        "            return match ? match.energy : null;\n",
        "        }));\n",
        "\n",
        "        Plotly.newPlot('plotly-3d', [{\n",
        "            z: zMat, x: xArr, y: yArr, type: 'surface', colorscale: 'Viridis'\n",
