        "            scene: { xaxis:{title:'EM'}, yaxis:{title:'Strong'}, zaxis:{title:'Energy'} }\n",
        "        });\n",
        "\n",
        "        // 2. Bipartite Purity (Polar Area)\n",
        "        new Chart(document.getElementById('purityPolar'), {\n",
        "            type: 'polarArea',\n",
        "            data: {\n",
        "                labels: audit.map(a => a.layer),\n",
        "                datasets: [{ data: audit.map(a => a.purity), backgroundColor: ['#0984e3', '#00b894', '#fdcb6e'] }]\n",
        "            },\n",
        "            options: { responsive: true, maintainAspectRatio: false, scales: { r: { display: false } } }\n",
