        "                }))\n",
        "            },\n",
        "            options: { responsive: true, maintainAspectRatio: false }\n",
        "        });\n",
        "\n",
        "        // 4. Entanglement Profile (Radar)\n",
        "        new Chart(document.getElementById('entRadar'), {\n",
        "            type: 'radar',\n",
        "            data: {\n",
        "                labels: audit.map(a => a.layer),\n",
        "                datasets: [{\n",
        "                    label: 'Entropy', data: audit.map(a => a.entropy),\n",
        "                    borderColor: '#d63031', backgroundColor: 'rgba(214, 48, 49, 0.2)', fill: true\n",
        "                }]\n",
        "            },\n",
        "            options: { responsive: true, maintainAspectRatio: false }\n",
        "        });\n",
        "    </script>\n",
        "</body>\n",
        "</html>\n",
        "\"\"\"\n",
        "\n",
        "# 3. Data Injection & Rendering\n",
        "final_html = html_content.replace('KPI_MIN_E', f\"{kpis['min_energy']:.4f}\")\\\n",
