        "\n",
        "bridge_obs = qml.PauliX(0) @ qml.PauliY(1) @ qml.PauliX(2) @ qml.PauliY(3)\n",
        "drive_obs = qml.PauliX(0) + qml.PauliX(1) + qml.PauliX(2) + qml.PauliX(3)\n",
        "\n",
        "# H_complex is our baseline, now augmented with interaction and driving terms\n",
        "H_bridge = H_complex + (bridge_coeff * bridge_obs) + (drive_coeff * drive_obs)\n",
        "\n",
        "# 2. Universal Entangler Ansatz: 20 Layers with CNOT Bridging\n",
        "def universal_entangler_ansatz(params, layers=20):\n",
        "    param_idx = 0\n",
        "    for l in range(layers):\n",
        "        for i in range(4):\n",
        "            qml.Rot(params[param_idx], params[param_idx+1], params[param_idx+2], wires=i)\n",
        "            param_idx += 3\n",
        "\n",
        "        # REFACTORED: CNOT Bridging Strategy\n",
        "        qml.CNOT(wires=[0, 3]) # Bridge: Nucleus to Vacuum\n",
        "        qml.CNOT(wires=[2, 3]) # Bridge: Electron Cloud to Vacuum\n",
        "\n",
        "        # Ising coupling for phase warping\n",
        "        for i in range(4):\n",
        "            qml.IsingXY(params[param_idx], wires=[i, (i + 1) % 4])\n",
        "            param_idx += 1\n",
        "\n",
        "        qml.MultiRZ(params[param_idx], wires=[0, 1, 2, 3])\n",
        "        param_idx += 1"
