        "import matplotlib.pyplot as plt\n",
        "import pennylane as qml\n",
        "from pennylane import numpy as np\n",
        "\n",
        "# --- 1. System Setup ---\n",
        "num_qubits = 4\n",
        "dev = qml.device(\"default.qubit\", wires=num_qubits)\n",
        "\n",
        "# Hamiltonian definitions\n",
        "coeffs = [2.5, 0.7, -1.2, 0.13, 0.45, 0.25]\n",
        "obs = [\n",
        "    qml.PauliZ(0) @ qml.PauliZ(1),\n",
        "    qml.PauliX(0),\n",
        "    qml.PauliZ(2),\n",
        "    qml.Identity(3),\n",
        "    qml.PauliZ(0) @ qml.PauliZ(2),\n",
        "    qml.PauliY(0) @ qml.PauliY(1)\n",
        "]\n",
        "H_complex = qml.Hamiltonian(coeffs, obs)\n",
        "\n",
        "bridge_coeff, drive_coeff = 2.0, 1.5\n",
        "bridge_obs = qml.PauliX(0) @ qml.PauliY(1) @ qml.PauliX(2) @ qml.PauliY(3)\n",
        "drive_obs = qml.PauliX(0) + qml.PauliX(1) + qml.PauliX(2) + qml.PauliX(3)\n",
        "H_bridge = H_complex + (bridge_coeff * bridge_obs) + (drive_coeff * drive_obs)\n",
        "\n",
        "# --- 2. Ansatz & QNodes ---\n",
        "def hyper_bridge_ansatz(params, layers=10):\n",
        "    param_idx = 0\n",
        "    for l in range(layers):\n",
        "        for i in range(4):\n",
        "            qml.Rot(params[param_idx], params[param_idx+1], params[param_idx+2], wires=i)\n",
        "            param_idx += 3\n",
        "        qml.CNOT(wires=[0, 3])\n",
        "        qml.CNOT(wires=[1, 2])\n",
        "        for i in range(4):\n",
        "            qml.CRX(params[param_idx], wires=[i, (i + 1) % 4])\n",
        "            param_idx += 1\n",
        "        qml.MultiRZ(params[param_idx], wires=[0, 1, 2, 3])\n",
        "        param_idx += 1\n",
        "\n",
        "@qml.qnode(dev)\n",
        "def get_nucleus_dm(params):\n",
        "    hyper_bridge_ansatz(params, layers=10)\n",
        "    return qml.density_matrix(wires=[0, 1])\n",
        "\n",
        "@qml.qnode(dev)\n",
        "def get_bridge_energy(params):\n",
        "    hyper_bridge_ansatz(params, layers=10)\n",
        "    return qml.expval(H_bridge)\n",
        "\n",
        "def composite_cost(params):\n",
        "    energy = get_bridge_energy(params)\n",
        "    rho = get_nucleus_dm(params)\n",
        "    evs = qml.math.eigvalsh(rho)\n",
        "    ent = -qml.math.sum(evs[evs > 1e-12] * qml.math.log2(evs[evs > 1e-12]))\n",
        "    return 0.1 * energy - 0.9 * ent\n",
        "\n",
        "# --- 3. Tracked Optimization Loop ---\n",
        "layers = 10\n",
        "total_params = layers * 17\n",
        "params = np.random.uniform(-np.pi, np.pi, total_params, requires_grad=True)\n",
        "\n",
        "opt = qml.AdamOptimizer(stepsize=0.05)\n",
        "entropy_history = []\n",
        "energy_history = []\n",
        "\n",
        "print(\"--- Starting Tracked Hyper-Bridge Optimization ---\")\n",
        "for i in range(100):\n",
        "    params, cost = opt.step_and_cost(composite_cost, params)\n",
        "\n",
        "    # Manual calculation for history tracking\n",
        "    current_energy = float(get_bridge_energy(params))\n",
        "    rho = get_nucleus_dm(params)\n",
        "    evs = qml.math.eigvalsh(rho)\n",
        "    current_ent = float(-qml.math.sum(evs[evs > 1e-12] * qml.math.log2(evs[evs > 1e-12])))\n",
        "\n",
        "    energy_history.append(current_energy)\n",
        "    entropy_history.append(current_ent)\n",
        "\n",
        "    if (i+1) % 20 == 0:\n",
        "        print(f\"Step {i+1:03d} | Cost: {cost:.4f} | Energy: {current_energy:.4f} | Entropy: {current_ent:.4f}\")\n",
        "\n",
        "# --- 4. Final Result Visualization ---\n",
        "fig, ax1 = plt.subplots(figsize=(10, 5))\n",
        "\n",
        "ax1.set_xlabel('Optimization Step')\n",
        "ax1.set_ylabel('Energy', color='tab:blue')\n",
        "ax1.plot(energy_history, color='tab:blue', label='Energy Path', linewidth=2)\n",
        "ax1.tick_params(axis='y', labelcolor='tab:blue')\n",
        "\n",
        "ax2 = ax1.twinx()\n",
        "ax2.set_ylabel('Von Neumann Entropy', color='tab:red')\n",
        "ax2.plot(entropy_history, color='tab:red', label='Entropy Path', linewidth=2)\n",
        "ax2.axhline(y=0.544, color='black', linestyle='--', alpha=0.6, label='Target Threshold (0.544)')\n",
