        "def dense_bridge_ansatz(params, layers=20):\n",
        "    param_idx = 0\n",
        "    for l in range(layers):\n",
        "        for i in range(4):\n",
        "            qml.Rot(params[param_idx], params[param_idx+1], params[param_idx+2], wires=i)\n",
        "            param_idx += 3\n",
        "\n",
        "        # DENSE TOPOLOGY: Enhanced coupling\n",
        "        # Replacing CNOT with CRX to introduce non-Z-basis rotation\n",
        "        qml.CRX(params[param_idx], wires=[0, 3])\n",
        "        param_idx += 1\n",
        "\n",
        "        qml.CNOT(wires=[1, 3])\n",
        "        qml.CNOT(wires=[2, 3])\n",
        "\n",
        "        for i in range(4):\n",
        "            qml.IsingXY(params[param_idx], wires=[i, (i + 1) % 4])\n",
        "            param_idx += 1\n",
        "        qml.MultiRZ(params[param_idx], wires=[0, 1, 2, 3])\n",
        "        param_idx += 1\n",
        "\n",
        "@qml.qnode(dev)\n",
        "def dense_cost(params):\n",
        "    dense_bridge_ansatz(params, layers=20)\n",
        "    return qml.expval(H_bridge)\n",
        "\n",
        "print(\"--- Optimizing Dense Bridge Topology (with CRX) ---\")\n",
        "# Update total_params to account for the new CRX angle per layer\n",
        "total_params_new = 20 * (12 + 1 + 4 + 1)\n",
        "res_dense = scipy.optimize.minimize(\n",
        "    dense_cost,\n",
        "    np.random.uniform(-np.pi, np.pi, total_params_new),\n",
        "    method='L-BFGS-B',\n",
        "    options={'maxiter': 50}\n",
        ")\n",
        "\n",
        "# Final Entropy check for Dense Bridge\n",
        "@qml.qnode(dev)\n",
        "def get_dense_entropy(params):\n",
        "    dense_bridge_ansatz(params, layers=20)\n",
        "    return qml.vn_entropy(wires=[0, 1])\n",
        "\n",
        "s_dense = float(get_dense_entropy(res_dense.x))\n",
