        "            qml.Rot(params[param_idx], params[param_idx+1], params[param_idx+2], wires=i)\n",
        "            param_idx += 3\n",
        "\n",
        "        # ENHANCED COUPLING: Direct Vacuum links\n",
        "        qml.CNOT(wires=[0, 3])  # Nucleus W0 to Vacuum W3\n",
        "        qml.CNOT(wires=[2, 3])  # Electron Cloud W2 to Vacuum W3\n",
        "        qml.CZ(wires=[1, 3])    # Nucleus W1 to Vacuum W3 (Phase coupling)\n",
        "\n",
        "        for i in range(4):\n",
        "            qml.IsingXY(params[param_idx], wires=[i, (i + 1) % 4])\n",
        "            param_idx += 1\n",
        "\n",
        "        qml.MultiRZ(params[param_idx], wires=[0, 1, 2, 3])\n",
        "        param_idx += 1\n",
        "\n",
        "@qml.qnode(dev)\n",
        "def enhanced_cost_fn(params):\n",
        "    enhanced_bridge_ansatz(params)\n",
        "    return qml.expval(H_bridge)\n",
        "\n",
        "# Re-optimizing with the enhanced vacuum bridge\n",
        "total_p_enhanced = 20 * (12 + 4 + 1)\n",
        "init_p_enhanced = np.random.uniform(-np.pi, np.pi, total_p_enhanced, requires_grad=True)\n",
        "\n",
        "print(\"--- Optimizing Enhanced Vacuum Bridge ---\")\n",
        "res_enhanced = scipy.optimize.minimize(\n",
        "    enhanced_cost_fn,\n",
        "    init_p_enhanced,\n",
        "    method='L-BFGS-B',\n",
        "    options={'maxiter': 200}\n",
        ")\n",
