        "plt.plot(test_depths, steps_needed, marker='s', color='darkgreen', linewidth=2, markersize=8)\n",
        "plt.title('Scaling Analysis: Optimization Speed vs. Circuit Depth')\n",
        "plt.xlabel('Number of Layers (Depth)')\n",
        "plt.ylabel('Iterations to reach S = 1.95')\n",
        "plt.grid(True, linestyle='--', alpha=0.6)\n",
        "\n",
        "# Adding a trendline to check for linear vs non-linear scaling\n",
